// pdf-fonts.js
// -----------------------------------------------------------------------
// Embeds "IBM Plex Sans" (Regular + Bold, Latin subset) into jsPDF so the
// Follow-Up Planned Report PDF (see web.js) can render text in a real,
// embedded font instead of jsPDF's built-in Helvetica.
//
// Font: IBM Plex Sans, (c) IBM Corp., licensed under the SIL Open Font
// License 1.1 (https://openfontlicense.org/) — free to embed/redistribute.
// Source: @fontsource/ibm-plex-sans (npm), latin-400/700-normal subsets,
// converted from WOFF2 to TTF for jsPDF's font converter.
//
// Usage (see web.js buildPdf()):
//   if (typeof registerPdfFonts_ === 'function') {
//       registerPdfFonts_(doc);        // registers both weights
//       doc.setFont('IBMPlexSans', 'normal');
//   }
// -----------------------------------------------------------------------
(function (global) {
    'use strict';

    var IBM_PLEX_SANS_REGULAR_BASE64 = '';

    var IBM_PLEX_SANS_BOLD_BASE64 = '';

    // Registers both weights of IBM Plex Sans under the jsPDF font family
    // name "IBMPlexSans". Call once per jsPDF document instance, before
    // any doc.setFont('IBMPlexSans', ...) calls.
    function registerPdfFonts_(doc) {
        if (!doc) throw new Error('registerPdfFonts_: a jsPDF document instance is required.');

        doc.addFileToVFS('IBMPlexSans-Regular.ttf', IBM_PLEX_SANS_REGULAR_BASE64);
        doc.addFont('IBMPlexSans-Regular.ttf', 'IBMPlexSans', 'normal');

        doc.addFileToVFS('IBMPlexSans-Bold.ttf', IBM_PLEX_SANS_BOLD_BASE64);
        doc.addFont('IBMPlexSans-Bold.ttf', 'IBMPlexSans', 'bold');

        return doc;
    }

    global.registerPdfFonts_ = registerPdfFonts_;
})(typeof window !== 'undefined' ? window : this);
